from typing import List

def solve(nums: List[int], queries: List[List[int]]) -> List[int]:
    import math

    def popcount_depth(num: int) -> int:
        depth = 0
        current = num
        while current > 0:
            current = bin(current).count('1')
            depth += 1
            if current == 1:
                break
        return depth

    # Precompute popcount depths for all numbers in nums
    depths = [popcount_depth(num) for num in nums]

    class SegmentTree:
        def __init__(self, data):
            self.n = len(data)
            self.size = 1
            while self.size < self.n:
                self.size <<= 1
            self.tree = [0] * (2 * self.size)
            self.lazy = [0] * (2 * self.size)
            # Fill the leaves
            for i in range(self.n):
                self.tree[self.size + i] = data[i]
            # Build the tree
            for i in range(self.size - 1, 0, -1):
                self.tree[i] = self.tree[2 * i] + self.tree[2 * i + 1]

        def push(self, node, l, r):
            if self.lazy[node] != 0:
                self.tree[node] = self.lazy[node] * (r - l + 1)
                if l != r:
                    self.lazy[2 * node] = self.lazy[node]
                    self.lazy[2 * node + 1] = self.lazy[node]
                self.lazy[node] = 0

        def update_range(self, node, l, r, ul, ur, val):
            self.push(node, l, r)
            if ur < l or ul > r:
                return
            if ul <= l and r <= ur:
                self.lazy[node] = val
                self.push(node, l, r)
                return
            mid = (l + r) // 2
            self.update_range(2 * node, l, mid, ul, ur, val)
            self.update_range(2 * node + 1, mid + 1, r, ul, ur, val)
            self.tree[node] = self.tree[2 * node] + self.tree[2 * node + 1]

        def query_range(self, node, l, r, ql, qr, k):
            self.push(node, l, r)
            if qr < l or ql > r:
                return 0
            if ql <= l and r <= qr:
                # Count how many elements are equal to k in this range
                if k == 0:
                    # For k=0, we need to count elements that eventually reach 1 with depth 0
                    # which is only possible if the number itself is 1
                    return self.tree[node] if l == r and self.tree[node] == 1 else 0
                else:
                    return self.tree[node] if l == r and self.tree[node] == k else 0
            mid = (l + r) // 2
            left = self.query_range(2 * node, l, mid, ql, qr, k)
            right = self.query_range(2 * node + 1, mid + 1, r, ql, qr, k)
            return left + right

    st = SegmentTree(depths)

    answer = []
    for query in queries:
        if query[0] == 1:
            l, r, k = query[1], query[2], query[3]
            res = st.query_range(1, 0, st.size - 1, l, r, k)
            answer.append(res)
        else:
            idx, val = query[1], query[2]
            new_depth = 0
            current = val
            while current > 0:
                current = bin(current).count('1')
                new_depth += 1
                if current == 1:
                    break
            st.update_range(1, 0, st.size - 1, idx, idx, new_depth)
    return answer
